mapper.select:
SELECT a.id, a.title, a.slug, a.summary, a.cover, a.view_count AS viewCount, a.is_top AS isTop, a.create_time AS createTime, c.name AS categoryName FROM blog_article a LEFT JOIN blog_category c ON a.category_id = c.id WHERE a.status = 1
AND a.title LIKE CONCAT('%', #{dto.keyword}, '%')
AND a.category_id = #{dto.categoryId}
AND a.id IN
#{id}
ORDER BY a.is_top DESC, a.create_time DESC

SELECT article_id
FROM blog_article_tag
WHERE tag_id = #{tagId}
